import{_ as o,y as s,a as d,o as l,a2 as a,D as r,g as i,I as n}from"./chunks/framework.DCcmcJcL.js";const b=JSON.parse('{"title":"EU Withdrawal","description":"","frontmatter":{},"headers":[],"relativePath":"orders/eu-withdrawal.md","filePath":"orders/eu-withdrawal.md","lastUpdated":1782394364000}'),h={name:"orders/eu-withdrawal.md"};function u(c,e,g,m,p,w){const t=s("ImagePopup");return l(),d("div",null,[e[0]||(e[0]=a('<h1 id="eu-withdrawal" tabindex="-1">EU Withdrawal <a class="header-anchor" href="#eu-withdrawal" aria-label="Permalink to &quot;EU Withdrawal&quot;">​</a></h1><p>The <strong>EU Withdrawal</strong> feature in Bagisto helps store owners comply with <strong>Directive (EU) 2023/2673 (Article 11a CRD)</strong> — the EU Consumer Rights Directive. It provides a legally compliant online withdrawal mechanism for EU consumers exercising their statutory 14-day right to withdraw from distance or off-premises contracts.</p><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><ul><li><strong>Online Withdrawal Form</strong> — A dedicated page for both authenticated customers and guests to submit withdrawal declarations.</li><li><strong>Admin Dashboard</strong> — Centralized management with DataGrid listing and detailed view with evidence timeline.</li><li><strong>Durable Medium Confirmation</strong> — Synchronous confirmation email serving as the legally required durable-medium artifact.</li><li><strong>Guest Withdrawal via Magic Link</strong> — Guests can withdraw using a temporary signed URL sent to their email.</li><li><strong>Rate Limiting</strong> — Security measures to prevent abuse (IP-based throttling on guest lookups and submissions).</li><li><strong>Append-Only Evidence</strong> — Withdrawal records are immutable after creation; evidence columns cannot be modified or deleted.</li><li><strong>One Withdrawal Per Order</strong> — Enforced at database, service, and UI levels.</li></ul><h2 id="admin-configuration" tabindex="-1">Admin Configuration <a class="header-anchor" href="#admin-configuration" aria-label="Permalink to &quot;Admin Configuration&quot;">​</a></h2><h3 id="enable-eu-withdrawal" tabindex="-1">Enable EU Withdrawal <a class="header-anchor" href="#enable-eu-withdrawal" aria-label="Permalink to &quot;Enable EU Withdrawal&quot;">​</a></h3><p><strong>Step 1:</strong> Navigate to <strong>Configure &gt; Sales &gt; EU Withdrawal</strong> in the Admin panel.</p><p><strong>Step 2:</strong> Toggle <strong>Enabled</strong> to enable the feature for the desired channel. This is a <strong>channel-based</strong> setting — each store channel can independently enable or disable the feature.</p><blockquote><p><strong>Important:</strong> Only enable on channels selling to EU consumers. When disabled for a channel, all withdrawal routes (including the public guest lookup) return 404, making the feature entirely invisible.</p></blockquote>',9)),r(t,{src:"/images/orders/eu-withdrawal.png",alt:"EU Withdrawal configuration"}),e[1]||(e[1]=a('<h2 id="admin-—-managing-withdrawals" tabindex="-1">Admin — Managing Withdrawals <a class="header-anchor" href="#admin-—-managing-withdrawals" aria-label="Permalink to &quot;Admin — Managing Withdrawals&quot;">​</a></h2><h3 id="viewing-all-withdrawals" tabindex="-1">Viewing All Withdrawals <a class="header-anchor" href="#viewing-all-withdrawals" aria-label="Permalink to &quot;Viewing All Withdrawals&quot;">​</a></h3><p>Navigate to <strong>Sales &gt; EU Withdrawals</strong>. The DataGrid displays:</p><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td><strong>Received At</strong></td><td>Date and time the withdrawal was submitted (sortable, filterable)</td></tr><tr><td><strong>Order ID</strong></td><td>The order increment ID (searchable, linked to the order)</td></tr><tr><td><strong>Customer Email</strong></td><td>Email used at checkout (searchable)</td></tr><tr><td><strong>Status</strong></td><td>Color-coded: <code>received</code> (yellow), <code>refunded</code> (green), <code>declined</code> (red)</td></tr><tr><td><strong>Channel</strong></td><td>The store channel code (filterable)</td></tr><tr><td><strong>Confirmation Sent At</strong></td><td>Timestamp of the durable-medium confirmation email</td></tr><tr><td><strong>Reference</strong></td><td>The public-facing withdrawal reference number (searchable)</td></tr></tbody></table>',4)),r(t,{src:"/images/orders/eu-grid.png",alt:"EU Withdrawal grid"}),e[2]||(e[2]=i("h3",{id:"viewing-withdrawal-details",tabindex:"-1"},[n("Viewing Withdrawal Details "),i("a",{class:"header-anchor",href:"#viewing-withdrawal-details","aria-label":'Permalink to "Viewing Withdrawal Details"'},"​")],-1)),e[3]||(e[3]=i("p",null,[n("Click "),i("strong",null,"View"),n(" on any record to see the full detail page with a two-column layout:")],-1)),r(t,{src:"/images/orders/eu-view.png",alt:"EU Withdrawal detail view"}),e[4]||(e[4]=a('<p><strong>Evidence Card:</strong></p><ul><li><strong>Received At</strong> — The legally effective timestamp (UTC).</li><li><strong>Reference UUID</strong> — Public-facing unique identifier (with copy-to-clipboard button).</li><li><strong>Order</strong> — Linked to the order detail page.</li><li><strong>Customer Email</strong> — The email used at checkout.</li><li><strong>Channel</strong> — The store channel.</li><li><strong>Locale</strong> — The language used when submitting.</li><li><strong>Reason</strong> — The customer&#39;s reason text, if provided.</li></ul><p><strong>Timeline Card:</strong> A step-by-step visual timeline showing:</p><ol><li><strong>Declaration Received</strong> — Always marked as done with the timestamp.</li><li><strong>Initial Confirmation Email</strong> — Shows sent timestamp (green), pending (grey), or warning (red with error message).</li><li><strong>Resolution</strong> — Shows <strong>Declined</strong> (with reason and admin who declined) <strong>or</strong> <strong>Refunded</strong> (with note and admin who processed it) <strong>or</strong> <strong>Pending</strong> (awaiting admin action).</li><li><strong>Final Confirmation Email</strong> — Shown only when a terminal state (refunded/declined) is reached.</li></ol><h3 id="admin-actions" tabindex="-1">Admin Actions <a class="header-anchor" href="#admin-actions" aria-label="Permalink to &quot;Admin Actions&quot;">​</a></h3><p>Three actions are available on the withdrawal detail page, each gated by ACL permissions:</p>',6)),r(t,{src:"/images/orders/eu-actions.png",alt:"EU Withdrawal Actions"}),e[5]||(e[5]=a('<h4 id="_1-resend-confirmation-email" tabindex="-1">1. Resend Confirmation Email <a class="header-anchor" href="#_1-resend-confirmation-email" aria-label="Permalink to &quot;1. Resend Confirmation Email&quot;">​</a></h4><p>Resends the durable-medium confirmation email to the customer. Useful if the initial send failed or the customer reports not receiving it.</p><ul><li>If the withdrawal is in a terminal state (refunded/declined), the email content adapts to reflect the final status.</li><li>If sending fails, the error message is stored.</li></ul><h4 id="_2-mark-as-refunded" tabindex="-1">2. Mark as Refunded <a class="header-anchor" href="#_2-mark-as-refunded" aria-label="Permalink to &quot;2. Mark as Refunded&quot;">​</a></h4><p>Records that a refund has been issued:</p><ol><li>Sets status to <code>refunded</code>.</li><li>Records <code>refunded_at</code> timestamp and <code>refunded_by_user_id</code> (the admin).</li></ol><blockquote><p><strong>Note:</strong> The actual refund processing (e.g., payment gateway reversal) must be handled separately. This action only records the refund in the withdrawal system.</p></blockquote><h4 id="_3-decline-withdrawal" tabindex="-1">3. Decline Withdrawal <a class="header-anchor" href="#_3-decline-withdrawal" aria-label="Permalink to &quot;3. Decline Withdrawal&quot;">​</a></h4><p>Records that the merchant contests the customer&#39;s entitlement to withdraw:</p><ol><li>Requires a <strong>Decline Reason</strong> (required, max 500 characters).</li><li>Sets status to <code>declined</code>.</li><li>Records <code>declined_at</code> timestamp and <code>declined_by_user_id</code>.</li><li>This action automatically <strong>clears</strong> any prior refund metadata (<code>refunded_at</code>, <code>refunded_by_user_id</code>, <code>refund_note</code> are set to null).</li></ol><blockquote><p><strong>Important:</strong> Since the database enforces one withdrawal per order and declined withdrawals cannot be re-submitted, use this action judiciously.</p></blockquote><h2 id="customer-—-withdrawing-from-a-contract-authenticated" tabindex="-1">Customer — Withdrawing from a Contract (Authenticated) <a class="header-anchor" href="#customer-—-withdrawing-from-a-contract-authenticated" aria-label="Permalink to &quot;Customer — Withdrawing from a Contract (Authenticated)&quot;">​</a></h2><h3 id="step-by-step-process" tabindex="-1">Step-by-Step Process <a class="header-anchor" href="#step-by-step-process" aria-label="Permalink to &quot;Step-by-Step Process&quot;">​</a></h3><p><strong>Step 1:</strong> Log in to the customer account and navigate to <strong>Orders</strong>.</p><p><strong>Step 2:</strong> Click <strong>View</strong> on the order you wish to withdraw from.</p><p><strong>Step 3:</strong> On the order detail page, click <strong>Withdraw from Contract</strong>.</p><ul><li>If a withdrawal already exists for this order, the button changes to <strong>View Your Withdrawal</strong> and redirects to the receipt page.</li></ul><p><strong>Step 4:</strong> Review the <strong>Withdrawal Form</strong> which includes:</p>',18)),r(t,{src:"/images/orders/eu-form.png",alt:"EU Withdrawal Form"}),e[6]||(e[6]=a("<ul><li><strong>Statutory Effect Notice</strong> — An amber warning: &quot;This is a legally binding declaration. By submitting this form......&quot;</li><li><strong>Order Summary</strong> — Order number, date, total, and item count.</li><li><strong>Reason (Optional)</strong> — A textarea field to optionally explain the reason for withdrawal.</li></ul><p><strong>Step 5:</strong> Click <strong>Submit</strong>.</p><p><strong>Step 6:</strong> You are redirected to the <strong>Receipt Page</strong> which displays:</p>",3)),r(t,{src:"/images/orders/eu-receipt.png",alt:"EU Withdrawal Receipt"}),e[7]||(e[7]=a('<ul><li><strong>Status Badge</strong> — &quot;Received&quot; in yellow, or &quot;Refunded&quot;/&quot;Declined&quot; if already processed.</li><li><strong>Received At</strong> — The legally effective timestamp.</li><li><strong>Reference</strong> — With a copy-to-clipboard button.</li><li><strong>Order</strong> — With a link back to the order.</li><li><strong>Customer Email</strong> — The email on file.</li><li><strong>Reason</strong> — The reason text (if provided).</li><li><strong>Next-Steps Timeline</strong> — Declaration Received → Confirmation Email → Resolution (Pending).</li><li><strong>Durable Medium Notice</strong> — &quot;We have recorded your declaration. This page and the email we just sent you both serve as confirmation on a durable medium.&quot;</li><li><strong>Print Button</strong> — Opens a print-friendly view.</li></ul><h2 id="guest-withdrawal" tabindex="-1">Guest Withdrawal <a class="header-anchor" href="#guest-withdrawal" aria-label="Permalink to &quot;Guest Withdrawal&quot;">​</a></h2><p>Guests can exercise their right of withdrawal without needing an account, using a secure public lookup flow.</p><h3 id="step-by-step-process-1" tabindex="-1">Step-by-Step Process <a class="header-anchor" href="#step-by-step-process-1" aria-label="Permalink to &quot;Step-by-Step Process&quot;">​</a></h3><p><strong>Step 1:</strong> Navigate to the <strong>Withdraw from a Contract</strong> link (found in the website header profile section).</p><p><strong>Step 2:</strong> The <strong>Public Lookup Form</strong> appears with two fields:</p>',6)),r(t,{src:"/images/orders/eu-guest.png",alt:"EU Withdrawal guest lookup form"}),e[8]||(e[8]=a(' <ul><li><strong>Order Number</strong> (required) — The order ID.</li><li><strong>Email Address</strong> (required) — The email used during checkout.</li></ul><p><strong>Step 3:</strong> Click <strong>Send me the withdrawal link</strong>.</p><p><strong>Important — Security:</strong> The system returns the <strong>same success message</strong> regardless of whether the order exists or matches. This prevents order-number enumeration attacks. If a matching guest order is found:</p><ul><li>A <strong>email link</strong> is queued (sent asynchronously to prevent timing leaks) with a temporary signed URL valid for <strong>24 hours</strong>.</li><li>If no match is found, no email is sent.</li></ul><p><strong>Step 4:</strong> Check your email inbox for the email link. Click the link to access the withdrawal form. The link is a <strong>signed URL</strong> with 24-hour validity.</p><p><strong>Step 5:</strong> Complete and submit the withdrawal form.</p><p><strong>Step 6:</strong> A <strong>durable-medium confirmation email</strong> is sent synchronously to your email address, and you are redirected to a signed receipt page.</p><h2 id="legal-compliance" tabindex="-1">Legal Compliance <a class="header-anchor" href="#legal-compliance" aria-label="Permalink to &quot;Legal Compliance&quot;">​</a></h2><h3 id="durable-medium-requirement-article-11a" tabindex="-1">Durable Medium Requirement (Article 11a) <a class="header-anchor" href="#durable-medium-requirement-article-11a" aria-label="Permalink to &quot;Durable Medium Requirement (Article 11a)&quot;">​</a></h3><p>The confirmation email sent synchronously upon withdrawal submission serves as the <strong>durable medium</strong> required by Article 11a(3) of Directive 2011/83/EU. Key design decisions:</p><ul><li><strong>Synchronous sending</strong> — The email is sent within the same request lifecycle (not queued), so a queue failure cannot leave a withdrawal without its legally required confirmation.</li><li><strong>Confirmation timestamp</strong> — <code>confirmation_sent_at</code> on the withdrawal record is the legally significant delivery record.</li><li><strong>Final confirmation</strong> — When an admin processes a withdrawal to a terminal state, <code>final_confirmation_sent_at</code> is recorded separately, preserving the original delivery evidence.</li><li><strong>Email footer</strong> — &quot;This message is the confirmation on a durable medium required by Article 11a of Directive 2011/83/EU on consumer rights...&quot;</li></ul><h2 id="statuses" tabindex="-1">Statuses <a class="header-anchor" href="#statuses" aria-label="Permalink to &quot;Statuses&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Description</th><th>Terminal</th></tr></thead><tbody><tr><td><code>received</code></td><td>Initial state — withdrawal has been submitted, awaiting admin action</td><td>No</td></tr><tr><td><code>refunded</code></td><td>Refund has been issued (recorded by admin)</td><td>Yes</td></tr><tr><td><code>declined</code></td><td>Merchant has contested the entitlement to withdraw</td><td>Yes</td></tr></tbody></table><h2 id="email-notifications" tabindex="-1">Email Notifications <a class="header-anchor" href="#email-notifications" aria-label="Permalink to &quot;Email Notifications&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Email Type</th><th>Sent When</th><th>Delivery Method</th><th>Content</th></tr></thead><tbody><tr><td><strong>Guest withdrawal email Link</strong></td><td>Guest lookup match found</td><td><strong>Queued</strong> (async)</td><td>Temporary signed URL valid for 24 hours</td></tr><tr><td><strong>Withdrawal Confirmation</strong></td><td>Withdrawal successfully submitted</td><td><strong>Synchronous</strong> (not queued)</td><td>Reference UUID, received_at, order, email, status, durable medium notice</td></tr><tr><td><strong>Final Confirmation</strong></td><td>Admin processes to terminal state + resends</td><td><strong>Synchronous</strong></td><td>Same as above but adapted for refunded/declined status</td></tr></tbody></table><p>The <strong>Withdrawal Confirmation</strong> email is the legal durable-medium artifact. Its subject adapts based on status:</p><ul><li><code>received</code>: &quot;Confirmation of your withdrawal -- Order :order_id&quot;</li><li><code>refunded</code>/<code>declined</code>: Same pattern but with updated status context.</li></ul>',18))])}const _=o(h,[["render",u]]);export{b as __pageData,_ as default};
